class Solution:
    def numberOfWays(self, n: int, x: int, y: int) -> int:
        MOD = 10**9 + 7
        dp = [[0] * (y + 1) for _ in range(n + 1)]
        dp[0][0] = 1

        for i in range(1, n + 1):
            for j in range(y + 1):
                for k in range(1, min(i, x) + 1):
                    if i - k >= 0:
                        dp[i][j] = (dp[i][j] + dp[i - k][j] * pow(y, k, MOD)) % MOD

        return dp[n][0]
